window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2021>1","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"The branch of crop science which deals with the study of insect pest is ?","images":[],"options":{"A":"zoology","B":"agronomy","C":"entomology","D":"pathology"},"answer":"C","explanation":"Entomology is the branch of crop science that deals with the study of insect pests. It involves studying the classification, life cycle, distribution, behavior, and impact of insects. Therefore, the correct option is 3.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>2","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Horse racing and polo are events where horses are used for","images":[],"options":{"A":"wildlife conservation","B":"recreation","C":"dowry payment","D":"transportation"},"answer":"B","explanation":"Horse racing and polo are sports events, hence they are used for recreational purposes. Wildlife conservation, dowry payment, and transportation are not the primary purposes of these events.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>3","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"Th construction rural feeder roads solves the following access problems in agriculture except","images":[],"options":{"A":"marketing","B":"transportation","C":"extension service","D":"land tenure system"},"answer":"D","explanation":"The construction of rural feeder roads primarily solves problems related to transportation, marketing, and extension services by providing better access to markets and services. However, it does not directly address issues related to the land tenure system, which involves the rights and arrangements for land ownership and use.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>4","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"The illustrated farm tool is used for","images":["data:image/jpeg;base64,"],"options":{"A":"making mounds","B":"transplanting  seedlings","C":"cutting trees","D":"pruning hedges"},"answer":"A","explanation":"The diagram illustrates a hoe . A hoe is used to dislodge weeds or for making cultivating the garden, stirring up and Moulding the soil.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>5","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The farm implement that could perform a similar function as the illustrated tool is","images":["data:image/jpeg;base64,"],"options":{"A":"plough","B":"harrow","C":"ridger","D":"cultivator"},"answer":"C","explanation":"A ridger could perform a similar function as a hoe , we can use a ridger to mound the soil , i.e to make heaps","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>6","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"A tractor-mounted sprayer used on large-scale farms is the","images":[],"options":{"A":"electrodyne sprayer","B":"motorised sprayer","C":"knapsack sprayer","D":"boom sprayer"},"answer":"D","explanation":"Boom sprayer is more suitable on large-scale farms other sprayers (electrodyne, motorised, Knapsack) are not  suitable on large-scale farms.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>7","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM POWER","question":"Which of the following types of farm power does not cause pollution","images":[],"options":{"A":"Hydro","B":"Electrical","C":"Mechanical","D":"chemical"},"answer":"B","explanation":"Electrical sources of farm power does not cause pollution  - mechanical source of farm power cold need fuel to power it when burned causes air pollution and sometimes noise pollution   - Hydro source of power could pollute the land and air   - chemical source of farm power can lead to water pollution","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>8","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : PRINCIPLES OF FARMSTEAD PLANNING","question":"In planning a farmstead, the structure which should be located on high elevation is the","images":[],"options":{"A":"fish pond","B":"pigsty","C":"farmhouse","D":"processing shed"},"answer":"C","explanation":"In planning a farmstead, living quarters should be located on the highest elevation to provide good view of the farm, The living quarters is the farmhouse","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>9","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"The process labelled I is","images":["data:image/jpeg;base64,"],"options":{"A":"evaporation","B":"absorption","C":"respiration","D":"transpiration"},"answer":"D","explanation":"The process labelled I is transpiration . Transpiration is the loss of water from living tissues of the aerial of plant in form of water vapour","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>10","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ENVIRONMENTAL FACTORS AFFECTING CROP AND ANIMAL DISTRIBUTION AND PRODUCTION","question":"The process labelled II is","images":["data:image/jpeg;base64,"],"options":{"A":"transpiration","B":"condensation","C":"evaporation","D":"respiration"},"answer":"C","explanation":"The process labelled II is evaporation , evaporation is a process by which water changes to gas or vapour . Evaporation is the primary pathway that water moves from the liquid state into the water cycle as atmospheric water cycle.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>11","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The major source of water to the plants in the diagrams is","images":["data:image/jpeg;base64,"],"options":{"A":"gravitational water","B":"hygroscopic water","C":"capillary water","D":"surface water"},"answer":"C","explanation":"The major source of water to the plants in diagram is capillary water , it should be noted that gravitational and hygroscopic water are not accessible to plants","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>12","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"The new formed when limestone is subjected to great heat and pressure is","images":[],"options":{"A":"slate","B":"graphite","C":"marble","D":"gneiss"},"answer":"C","explanation":"When limestone is subjected to great heat and pressure, it forms marble. This process is known as metamorphism. Marble is a metamorphic rock that is formed when limestone is subjected to high temperature and pressure over a long period of time.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>13","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRO-ALLIED INDUSTRIES AND RELATIONSHIP BETWEEN AGRICULTURE AND INDUSTRY","question":"Which of the following pairs of raw materials used in the canning industry ?","images":[],"options":{"A":"meat and fish","B":"cotton and tea","C":"Hide and skin","D":"pulpwood and cocoa"},"answer":"A","explanation":"Meat and fish are used in canning industry , canning industry pressure foods in cans. Meat and fish are examples of food that can be processed and preserved in cans.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>14","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Microorganism that decompose organic matter will function best under","images":[],"options":{"A":"waterlogged soil condition","B":"anaerobic soil condition","C":"low soil temperature","D":"optimum soil pH"},"answer":"D","explanation":"Microorganisms that decompose organic matter, also known as decomposers, function best under optimum soil pH. Soil pH is a measure of the acidity or alkalinity of the soil. An optimum pH level (close to neutral, pH 7) allows for the best growth and functioning of these microorganisms. Waterlogged and anaerobic soil conditions, as well as low soil temperatures, can inhibit the activity of these microorganisms.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>15","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"In an experiment  to determine the percentage of organic matter in a soil sample, The following data was collected :  weight of oven-dried soil before burning =50g  weight of oven-dried soil after burning  = 28g    Calculate the weight of organic matter in the soil","images":[],"options":{"A":"11g","B":"22g","C":"44g","D":"78g"},"answer":"B","explanation":"Parameters given :  weight of oven-dried soil before burning  = 50g  weight of  oven-dried soil before burning  = 28g  weight of organic matter = 50g-  28g  = 22g","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2021>16","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"In an experiment  to determine the percentage of organic matter in a soil sample, The following data was collected :  weight of oven-dried soil before burning =50g  weight of oven-dried soil after burning  = 28g  Determine the percentage of organic matter in the soil","images":[],"options":{"A":"22%","B":"44%","C":"56%","D":"60%"},"answer":"B","explanation":"The percentage of organic matter in the soil can be calculated by subtracting the weight of the oven-dried soil after burning from the weight before burning, and then dividing by the weight before burning. Therefore, the percentage of organic matter is ((50g - 28g) / 50g) * 100% = 44%. Hence, the correct option is 2.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>17","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"Which of the following practices will improve clay soil ?","images":[],"options":{"A":"use of acid-forming fertilizers","B":"bush burning","C":"addition of sodium chloride","D":"addition of organic material"},"answer":"D","explanation":"Clay soil is dense and has poor drainage. Adding organic material improves the soil structure, increases its ability to hold and release nutrients, and improves its drainage and water-holding capacity. Therefore, the correct answer is 'addition of organic material'.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>18","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"A farmer  practice crop rotation in order to","images":[],"options":{"A":"reduce yield","B":"improve soil texture","C":"increase pest incidence","D":"improve soil fertility"},"answer":"D","explanation":"A farmer practises crop rotation in order to improve soil fertility. Crop rotation is practice of planting  different  crops on the same plot of land to improve soil health, optimize nutrient in the soil, combat pest and weed pressure","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>19","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The phosphorus cycle is described as being sedimentary because phosphorus","images":[],"options":{"A":"is a macro element","B":"is an earth bound element","C":"is solid at room temperature","D":"occurs in the atmosphere"},"answer":"B","explanation":"The phosphorus cycle is a sedimentary cycle (unlike carbon, oxygen and nitrogen),The atmosphere is not a reservoir for phosphorus nor do micro organism fix phosphorus as they do nitrogen. Phosphorus enters the biosphere almost entirely from the soil through absorption by plant roots","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>20","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The following factors are essential for maize production except","images":[],"options":{"A":"high temperature","B":"low temperature","C":"relative humility","D":"adequate rainfall"},"answer":"A","explanation":"High temperature is not essential for maize production, An increase  in temperature , above 23oC causes a reduction in maize yield , which is even more accentuated when the daily value exceeds 30oC","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>21","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : AGRICULTURAL POLLUTION","question":"Drying of newly harvested grains before storage helps to increase the","images":[],"options":{"A":"moisture content","B":"pest incidence","C":"seed viability","D":"nutrient content"},"answer":"C","explanation":"Drying of newly harvested grains before storage helps to increase the seed viability , i.e it helps to increase the number of seeds that are alive after storage . The greater the viability of your  seeds , the fewer seeds with be needed to established a desired number of plants in the field or nursery","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>22","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Yams stored in a barn should be inspected at least once a week in order to ?","images":[],"options":{"A":"remove irregular shaped tubers","B":"control termite attack","C":"prevent mouldiness in yam","D":"remove sprouts and rotten tubers"},"answer":"D","explanation":"Yams stored in a barn should be inspected at least once a week to remove sprouts and rotten tubers. This is because sprouts and rotten tubers can affect the quality of the yams and can also spread rot to other yams in the barn.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>23","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"The botanical name of onion is","images":[],"options":{"A":"Zea mays","B":"Oryza sativa","C":"Carica papaya","D":"Allium cepa"},"answer":"D","explanation":"The botanical name of onion is  Allium cepa . Botanical names are the scientific names given to plants and they are universally accepted and used to avoid confusion that can arise from the use of common names.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>24","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Okro seeds are shown on 0.72 hectares of farmland at a spacing of 60cm by 60cm. Calculate the expected lant population.","images":[],"options":{"A":"3,600 plants","B":"7,200 plants","C":"10,000 plants","D":"20,000 plants"},"answer":"D","explanation":"1 hectares = 10,000m2  0.72 hectares = x  x = 7,200  Area of spacing = 60cm x 60cm = 3600 x 10-4 = 0.36m2  No of plants = 7200/0.36 = 2 x 104 = 20,000 plants","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>25","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"A plot of land devoted to the cultivation of fruit tree  is called","images":[],"options":{"A":"orchard","B":"farmstead","C":"forest","D":"ranch"},"answer":"A","explanation":"An orchard is a type of land where fruit trees are grown. It is a dedicated area for the cultivation of fruit trees. A farmstead is a farm and its adjacent buildings, a forest is a large area covered with trees and undergrowth, and a ranch is a large farm, especially in the US, where cattle or other animals are bred and raised.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>26","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Two species of kola grown for commercial purposes in West africa are","images":[],"options":{"A":"Cola acuminata and  Cola gigantea","B":"Cola nitida and  Cola verticillata","C":"Cola nitida and  Cola acuminata","D":"Cola verticillata and  cola gigantea"},"answer":"C","explanation":"The two species of kola grown for commercial purposes in West Africa are  Cola nitida and  Cola acuminata .  Cola nitida is also known as 'kola nut' and is native to the tropical rainforests of Africa.  Cola acuminata is another species of kola nut. Both are used for their caffeine content and in traditional medicine.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>27","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"propagation of ginger is generally done using its","images":[],"options":{"A":"corm","B":"rhizome","C":"sucker","D":"seed"},"answer":"B","explanation":"Ginger is generally propagated using its rhizome. A rhizome is a modified subterranean plant stem that sends out roots and shoots from its nodes. In the case of ginger, the rhizome is the part that is commonly used in cooking. It can also be planted to produce new plants.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>28","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Elaeis guineensis  and  Arachis hypogaea are examples of","images":[],"options":{"A":"Latex crops","B":"oil crops","C":"fibre crops","D":"fruit crops"},"answer":"B","explanation":"Elaeis guineensis  is the scientific name for oil palm, and  Arachis hypogaea is the scientific name for groundnut. Both of these plants are known for their oil-producing properties, hence they are classified as oil crops.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>29","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Which of the following statement is not a reason for carrying out the illustrated farm operation ? To","images":["data:image/jpeg;base64,"],"options":{"A":"expose the leaves to sunlight","B":"prevent damage by rodents.","C":"Improve the yield of the crops","D":"prevent lodging of the plants"},"answer":"B","explanation":"The farm operation illustrated is staking . staking is nt done to prevent damage by rodents.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>30","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Crops which require the illustrated farm operation are","images":["data:image/jpeg;base64,"],"options":{"A":"yam and cowpea","B":"tomato and okro","C":"okro and pepper","D":"tomato and yam"},"answer":"D","explanation":"Crop which require staking include tomato and yam.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>31","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"The basic importance of agriculture to a forester","images":[],"options":{"A":"obtain honey","B":"obtain food","C":"acquire labour","D":"procure timber"},"answer":"D","explanation":"The basic importance of agriculture to forester is to produce timber.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>32","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ORNAMENTAL PLANTS :","question":"A suitable grass lawns is","images":[],"options":{"A":"Androgon gayanus","B":"Pennisetum purpureum","C":"Cynodon dactylon","D":"Panicum maximum"},"answer":"C","explanation":"Cynodon dactylon , also known as Bermuda grass, is a suitable grass for lawns. It is a widely used species in warm regions, known for its resistance to drought and heavy traffic. It forms a dense and fine-textured lawn that is easy to mow and maintain.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>33","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The causative organism of maize rust is a","images":[],"options":{"A":"bacterium","B":"protozoon","C":"virus","D":"fungus"},"answer":"D","explanation":"Maize rust is caused by a fungus known as Puccinia sorghi. Fungi are a group of organisms that include yeasts, molds, and mushrooms. They are different from bacteria, viruses, and protozoa in their complexity and the diseases they cause.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>34","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"which of the following groups of insect pests damage crops by biting and chewing ?","images":[],"options":{"A":"cotton stainer, armyworm and cricket","B":"cricket, mealybug and whitefly","C":"Armyworm, termite and grasshopper","D":"cotton stainer, mealybug and termite"},"answer":"C","explanation":"Armyworms, termites , beetles, caterpillar of moths , cricket, flies , locust, grasshopper and so on are common biting and chewing insects pests.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>35","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The breeds of cattle resistant to trypanosomiasis are","images":[],"options":{"A":"N'dama and Muturu","B":"white fulani and Biu","C":"Red Bororo and Adamawa","D":"Wadara and sokoto Gudali"},"answer":"A","explanation":"N'daa and west African shorthorn cattle also called Muturu are cattle breeds resistant to trypanosomiasis","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>36","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Which of the following feature is not a characteristic of a good layer ?","images":[],"options":{"A":"Bright red comb and wattle","B":"Long and curve beak","C":"Bright and bulging eyes","D":"Broad and flexible pelvic bone"},"answer":"B","explanation":"A good layer, in the context of poultry, refers to a hen that is a good egg producer. Characteristics of a good layer include a bright red comb and wattle, bright and bulging eyes, and a broad and flexible pelvic bone. These characteristics indicate good health and egg production capacity. A long and curved beak, however, is not a characteristic of a good layer. The shape of the beak does not influence egg production.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>37","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"The best way for a young animal to obtain colostrum is by","images":[],"options":{"A":"giving its powdered milk","B":"providing it with warm milk","C":"injecting it with progesterone","D":"allowing it to suckle the dam"},"answer":"D","explanation":"Colostrum is the first milk produced by mammals after giving birth. It is rich in antibodies and nutrients, and it is crucial for the newborn's immune system. The best way for a young animal to obtain colostrum is by suckling the dam (mother). This is because the antibodies in colostrum are large proteins that are not easily absorbed in any other way than through the gut of the newborn. Therefore, options such as giving powdered milk or injecting progesterone do not provide the same benefits.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>38","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"Which of the following statement about slatted floors in livestock housing are True? They   I. Lessen labour requirement   II. reduce odour in pens   III. Hamper movement of animals","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I,II and III only"},"answer":"A","explanation":"Slatted floors in livestock housing are designed to allow waste to fall through the gaps, reducing the need for manual cleaning (lessening labour requirement) and reducing odour in pens. However, they do not hamper the movement of animals. In fact, they are designed to be comfortable for the animals to walk on. Therefore, statements I and II are true, while statement III is false.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2021>39","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"If 0.7kg of feed was fed to chicks per week, determine the cost of feeding the birds for 6 weeks . (1kg of feed cost \u20a65)","images":[],"options":{"A":"\u20a64.20","B":"\u20a611.70","C":"\u20a621.00","D":"\u20a630.00"},"answer":"C","explanation":"parameters given   per week, 0.7kg of feed was consumed   6 weeks = x  16=0.7x  1kg = \u20a65  4.2kg = x   x =   21.0 Naira","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>40","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Feeds that have more than 18% fibre are classified as","images":[],"options":{"A":"concentrates","B":"addictive","C":"supplements","D":"roughages"},"answer":"D","explanation":"Feeds that have more than 18% fibre are classified as roughages. Roughages are feeds that are high in fiber and low in digestible nutrients. They are typically used to provide bulk to the diet of ruminant animals and to stimulate their digestive system.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>41","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"An advantage of zero-grazing is that it","images":[],"options":{"A":"requires a lot of labour","B":"prevents livestock from physical exercises","C":"prevents depletion of pasture","D":"increase the cost of pasture management"},"answer":"C","explanation":"zero-grazing prevents the depletion of pasture , zero grazing is a system where the cattle are usually kept in the farm nd farmers bring the feed (grass) and water the animals. few of the advantages of zero-gazing is to help reduce animal pressure on the land and limit the spread of diseases amongst animals.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>42","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The illustrated tool is","images":["data:image/jpeg;base64,"],"options":{"A":"an elastrator","B":"a burdizzo","C":"an electric dehoner","D":"an artifical vargina"},"answer":"D","explanation":"The illustrated tol is an artificial vagina. An artificial vagina is a device used primarily in animal reproduction, particularly in the breeding of livestock such as cattle, horses, and sheep.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>43","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"The illustrated tool is used for","images":["data:image/jpeg;base64,"],"options":{"A":"castrating the bull calf","B":"cutting the horns of the animal","C":"collecting semen from the bull","D":"identifying the animal"},"answer":"C","explanation":"Artificial vaginal is used to collect semen from the bull","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2021>44","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Formation of blisters on the mouth and the skin around the hoof of farm animals is a symptom of","images":[],"options":{"A":"Rinderpest","B":"anthrax","C":"Newcastle disease","D":"foot and mouth disease"},"answer":"D","explanation":"This is a symptoms of food-and-mouth disease (FMD), also called hoof-and-mouth disease or aftosa , highly contagious viral disease affecting practically all cloven-footed domesticated mammals, including cattle, sheep , goat and pigs.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>45","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"In sheep production, tapeworm could be controlled by","images":[],"options":{"A":"dusting","B":"spraying","C":"dipping","D":"drenching"},"answer":"D","explanation":"Drenching is the process of forced pouring of liquid preparation down the throat of each sheep to kill internal parasites such as tapeworms. Dipping involves applying a chemical solution to kill external parasites , often by getting the sheep saturated","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>46","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"Pricequantity supplied (kg)2448016400    The percentage change in quantity supplied for maize is","images":[],"options":{"A":"16.7%","B":"20%","C":"80%","D":"83.3%"},"answer":"A","explanation":"Q2 = 400  Q1 = 480  \u2206Q = 480 - 400 = 80   = %\u2206Q = 80/480 x 100 = 1/6 x 100 = 16.67%.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>47","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"Pricequantity supplied (kg)2448016400  Calculate the percentage change in price for maize","images":[],"options":{"A":"8.0%","B":"33.3%","C":"50.0%","D":"66.7%"},"answer":"B","explanation":"The percentage change in price is calculated by subtracting the new price from the old price, dividing the result by the old price, and then multiplying by 100. Therefore, the percentage change in price is ((24-16)/24)*100 = 33.3%.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2021>48","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"Pricequantity supplied (kg)2448016400  Determine the elasticity of supply for maize","images":[],"options":{"A":"0.3","B":"0.4","C":"0.5","D":"0.6"},"answer":"C","explanation":"The elasticity of supply is calculated by dividing the percentage change in quantity supplied by the percentage change in price. Therefore, the elasticity of supply is 16.67%/33.3% = 0.5.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2021>49","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"A long term loan for an agricultural enterprise could be obtained from","images":[],"options":{"A":"microfinance bank","B":"commercial bank","C":"money lenders","D":"cooperative societies"},"answer":"B","explanation":"A long term loan for an agricultural enterprise could be obtained from a commercial bank. Commercial banks are financial institutions that provide a variety of services, including loans. They are capable of providing long term loans, unlike microfinance banks, money lenders, and cooperative societies which typically provide short term loans.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2021>50","subject":"Agricultural Science","year":"2021","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"Which of the following problems of agriculture could be solved through farmers' adoption of research findings?","images":[],"options":{"A":"unpredictable climate","B":"Environmental degradation","C":"poor extension service","D":"insufficient basic amenities"},"answer":"C","explanation":"Research and extension system plays a crucial  role in agricultural development. They are central to realizing the potential of agricultural innovation","marks":"1","difficulty":"2"}];